import axios from 'axios';

const API_BASE_URL = 'http://localhost:5000/product-types';

export const getProductTypes = () => axios.get(API_BASE_URL);
export const getProductType = (id) => axios.get(`${API_BASE_URL}/${id}`);
export const createProductType = (data) => axios.post(API_BASE_URL, data);
export const updateProductType = (id, data) => axios.put(`${API_BASE_URL}/${id}`, data);
export const deleteProductType = (id) => axios.delete(`${API_BASE_URL}/${id}`);
